// Extract candidate reply info
const items = $input.all();

return items.map(item => {
  const email = item.json;
  return {
    json: {
      from_email: email.from?.value?.[0]?.address || email.from || '',
      from_name: email.from?.value?.[0]?.name || '',
      subject: email.subject || '',
      body_text: email.text || email.snippet || '',
      received_date: email.date || new Date().toISOString(),
      thread_id: email.threadId || '',
      message_id: email.id || '',
    }
  };
});

// Validate the requested date against weekends & holidays, or find next available
const items = $input.all();

const holidays2026 = [
  '2026-01-26','2026-03-10','2026-04-03','2026-04-14',
  '2026-05-01','2026-08-15','2026-08-19','2026-09-25',
  '2026-10-02','2026-10-12','2026-11-02','2026-11-03',
  '2026-11-19','2026-12-25'
];

function isBusinessDay(dt) {
  if (dt.weekday === 6 || dt.weekday === 7) return false;
  return !holidays2026.includes(dt.toFormat('yyyy-MM-dd'));
}

function getNextBusinessDay(fromDate) {
  let d = fromDate.plus({ days: 1 });
  let attempts = 0;
  while (!isBusinessDay(d) && attempts < 10) {
    d = d.plus({ days: 1 });
    attempts++;
  }
  return d;
}

const now = DateTime.now().setZone('Asia/Kolkata');
const proposedDate = getNextBusinessDay(now);

return items.map(item => ({
  json: {
    ...item.json,
    new_proposed_date: proposedDate.toFormat('yyyy-MM-dd'),
    new_proposed_time: '10:00 AM IST',
    new_proposed_day: proposedDate.toFormat('EEEE, MMMM dd, yyyy'),
  }
}));
